import { z } from "zod";
import type { Tool } from "./types.js";

// {{summary}}
const schema = z.object({ input: z.string() });

export const {{name}}: Tool = {
  schema: {
    name: "{{name}}",
    description: "{{summary}}",
    parameters: { type: "object", properties: { input: { type: "string" } }, required: ["input"] },
  },
  // Send only the risk-relevant part to the kernel (never file contents).
  describeForSafety: (args) => `{{name}} ${String((args as { input?: string }).input ?? "")}`,
  async execute(rawArgs) {
    const parsed = schema.safeParse(rawArgs);
    if (!parsed.success) return { ok: false, output: "{{name}}: invalid args — expected { input: string }" };
    // TODO: real logic; return a real value, never a stub.
    return { ok: true, output: `{{name}} ran on: ${parsed.data.input}` };
  },
};

import { describe, it, expect } from "vitest";
import { {{name}} } from "./{{name}}.js";

describe("{{name}}", () => {
  it("runs on valid input", async () => {
    const r = await {{name}}.execute({ input: "x" }, {} as never);
    expect(r.ok).toBe(true);
  });
  it("rejects invalid args as a value (never throws)", async () => {
    const r = await {{name}}.execute({}, {} as never);
    expect(r.ok).toBe(false);
  });
});
